#define ENA 9   // PWM speed control
#define IN1 8   // Direction pin 1
#define IN2 7   // Direction pin 2
void setup() {
  pinMode(ENA, OUTPUT);
  pinMode(IN1, OUTPUT);
  pinMode(IN2, OUTPUT);
}
void loop() {
  // Forward at 75% speed
  digitalWrite(IN1, HIGH);
  digitalWrite(IN2, LOW);
  analogWrite(ENA, 191); // 0-255
  delay(2000);
  // Reverse
  digitalWrite(IN1, LOW);
  digitalWrite(IN2, HIGH);
  analogWrite(ENA, 191);
  delay(2000);
  // Stop
  analogWrite(ENA, 0);
  delay(1000);
}
